"use strict";parserFactory.register("helheimscans.com",()=>new HelheimscansParser),parserFactory.register("helheimscans.org",()=>new HelheimscansParser),parserFactory.register("helioscans.com",()=>new HelheimscansParser);class HelheimscansParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("#chapters_panel a")].map(this.linkToChapter).reverse()}linkToChapter(e){let r=e.querySelector("span").textContent.trim(),t=e.querySelector("img");return{sourceUrl:e.href,title:r,isIncludeable:null==t}}findContent(e){return e.querySelector("#pages")}preprocessRawDom(e){let r=[...e.querySelectorAll("#pages img.lazy[uid]")];for(let e of r)e.src=`https://image.meowing.org/uploads/${e.getAttribute("uid")}`}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("title")}findCoverImageUrl(e){let r=e.querySelector("div[style^=--photo]");return r=r.getAttribute("style").split("(")[1],r?r.substring(0,r.length-1):null}getInformationEpubItemChildNodes(e){let r=e.querySelector("meta[name='description']");if(r){let t=e.createElement("p");return t.textContent=r.getAttribute("content"),[t]}return[]}}